            return f"{s} spent {o} minutes in space"
        if p == "mission":
            return f"{s} flew on the {o} mission"
        if p == "selectedByNasa":
            return f"{s} was selected by NASA in {o}"
        if p == "deathDate":
            return f"{s} died on {o}"
        if p == "nationality":
            return f"{s} was a {o} national"
        if p == "servedAsChiefOfTheAstronautOfficeIn":
            return f"{s} served as chief of the Astronaut Office in {o}"
        if p == "title":
            return f"{s}'s title is {o}"
        if p == "ribbonAward":
            return f"{s} received the {o} ribbon award"
        if p == "operator":
            return f"{s} was operated by {o}"
        if p == "backupPilot":
            return f"The backup pilot of {s} was {o}"
        if p == "commander":
            return f"The commander of {s} was {o}"
        if p == "crewMembers":
            return f"The crew members of {s} include {o}"
        if p == "representative":
            return f"The representative of {s} is {o}"
        if p == "alternativeName":
            return f"{s} is also known as {o}"
        if p == "awards":
            return f"{s} received {o} awards"
